mapper.select:
/** TelCounsel_Query.selectTelCounsel 전화상담 기본정보 1건 조회 (상세 내역 포함 ) */
select

from
    NMCP_TEL_COUNSEL_BAS TCB
where
    COUNSEL_SEQ = #{counselSeq}

/** TelCounsel_Query.selectTelCounselList 전화상담 기본정보 리스트 조회 */ select , TCD.COUNSEL_DTL_SEQ AS D_COUNSEL_DTL_SEQ, TCD.COUNSEL_SEQ AS D_COUNSEL_SEQ, TCD.REPLY_CONTENT AS D_REPLY_CONTENT, TCD.REPLY_STAT_CD AS D_REPLY_STAT_CD, TCD.DEL_YN AS D_DEL_YN, TCD.CRET_ID AS D_CRET_ID, TCD.AMD_ID AS D_AMT_ID, TCD.CRET_DT AS D_CRET_DT, TCD.AMD_DT AS D_AMD_DT from NMCP_TEL_COUNSEL_BAS TCB left outer join NMCP_TEL_COUNSEL_DTL TCD on TCB.LAST_COUNSEL_DTL_SEQ = TCD.COUNSEL_DTL_SEQ where 1=1
and TCB.COUNSEL_CTG = #{counselCtg}
and TCB.REGION_CD = #{regionCd}
and TCB.AGE_CD = #{ageCd}
and TCB.GENDER_CD = #{genderCd}
and TCD.REPLY_STAT_CD = #{replyStatCd}
and TCB.COUNSEL_NM LIKE '%'||#{searchValue}||'%'
and TCB.MOBILE_NO LIKE '%'||#{searchValue}||'%'
and TO_CHAR(TCB.CRET_DT,'yyyy.mm.dd') = #{searchDtReq}
and TO_CHAR(TCD.CRET_DT,'yyyy.mm.dd') = #{searchDtAnswer}
order by CRET_DT desc

/** TelCounsel_Query.selectTelCounselListCount 전화상담 기본정보 리스트 COUNT 조회 */
select
    COUNT(1)
from
    NMCP_TEL_COUNSEL_BAS TCB
left outer join
    NMCP_TEL_COUNSEL_DTL TCD on TCB.LAST_COUNSEL_DTL_SEQ = TCD.COUNSEL_DTL_SEQ
where
    1=1

    and TCB.COUNSEL_CTG = #{counselCtg}


    and	TCB.REGION_CD = #{regionCd}


    and TCB.AGE_CD = #{ageCd}


    and TCB.GENDER_CD = #{genderCd}


    and TCD.REPLY_STAT_CD = #{replyStatCd}




        and TCB.COUNSEL_NM LIKE '%'||#{searchValue}||'%'


        and TCB.MOBILE_NO LIKE '%'||#{searchValue}||'%'




    and TO_CHAR(TCB.CRET_DT,'yyyy.mm.dd') = #{searchDtReq}


    and TO_CHAR(TCD.CRET_DT,'yyyy.mm.dd') = #{searchDtAnswer}

mapper.update:
/** TelCounsel_Query.updateTelCounselDtl 전화상담정보 상세 수정 */ update NMCP_TEL_COUNSEL_DTL TCD set TCD.AMD_DT = sysdate,
TCD.REPLY_CONTENT = #{replyContent},
TCD.REPLY_STAT_CD = #{replyStatCd},
TCD.DEL_YN = #{delYn},
TCD.AMD_ID = #{amdId} where TCD.COUNSEL_DTL_SEQ = #{counselDtlSeq}

mapper.insert:
SELECT SQ_TEL_COUNSEL_BAS_DTL_SEQ.NEXTVAL FROM DUAL
insert into NMCP_TEL_COUNSEL_DTL TCD (
) values ( #{counselDtlSeq}, #{counselSeq}, #{replyContent}, #{replyStatCd}, 'N', #{cretId}, null, sysdate, null )

mapper.select:
        /** TelCounsel_Query.selectCtiTelCounselCnt */
		SELECT COUNT(1)
		  FROM NMCP_TEL_COUNSEL_BAS
		 WHERE 1=1
		   AND MOBILE_NO = #{mobileNo}
		   AND TO_CHAR(CRET_DT,'YYYYMMDD') BETWEEN TO_CHAR(SYSDATE-30,'YYYYMMDD') AND TO_CHAR(SYSDATE,'YYYYMMDD')
